#!/usr/bin/env bash
# Submit the full-component FLUX KNOT rebuild/upload Cloud Build.
#
# This intentionally builds a tiny source context instead of uploading the
# whole monorepo. The Cloud Build config still sees the same repo-relative paths
# it expects under /workspace/open-source/gnosis.

set -euo pipefail

ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/../../.." && pwd)"
PROJECT_ID="${PROJECT_ID:-neutral-418500}"
BUILD_CONFIG="$ROOT/open-source/gnosis/cloudbuild-flux-knots.yaml"
CONTEXT_DIR="$(mktemp -d "${TMPDIR:-/tmp}/flux-knot-cloudbuild-src.XXXXXX")"

cleanup() {
  rm -rf "$CONTEXT_DIR"
}
trap cleanup EXIT

mkdir -p "$CONTEXT_DIR/open-source/gnosis/distributed-inference"
cp "$BUILD_CONFIG" "$CONTEXT_DIR/open-source/gnosis/cloudbuild-flux-knots.yaml"
cp \
  "$ROOT/open-source/gnosis/distributed-inference/encode-knot.py" \
  "$CONTEXT_DIR/open-source/gnosis/distributed-inference/encode-knot.py"
cp \
  "$ROOT/open-source/gnosis/distributed-inference/upload-to-r2.py" \
  "$CONTEXT_DIR/open-source/gnosis/distributed-inference/upload-to-r2.py"

echo "[flux-knot] submitting Cloud Build in project ${PROJECT_ID}"
echo "[flux-knot] source context:"
find "$CONTEXT_DIR" -maxdepth 5 -type f -print

gcloud builds submit "$CONTEXT_DIR" \
  --project "$PROJECT_ID" \
  --config "$CONTEXT_DIR/open-source/gnosis/cloudbuild-flux-knots.yaml" \
  --async \
  --format='value(id)'
